1	export type Cell = [number, number];
2	
3	export function nextGeneration(livingCells: Cell[]): Cell[] {
4	  const key = (x: number, y: number) => `${x},${y}`;
5	  const liveSet = new Set(livingCells.map(([x, y]) => key(x, y)));
6	  const neighborCounts = new Map<string, number>();
7	
8	  for (const [x, y] of livingCells) {
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        const k = key(x + dx, y + dy);
13	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
14	      }
15	    }
16	  }
17	
18	  const result: Cell[] = [];
19	  for (const [k, count] of neighborCounts) {
20	    const survives = count === 3 || (count === 2 && liveSet.has(k));
21	    if (survives) {
22	      const [x, y] = k.split(",").map(Number) as Cell;
23	      result.push([x, y]);
24	    }
25	  }
26	  return result;
27	}
